// Get posts from IG response
const data = $input.first().json.data || [];

// Read last seen ID from static data (persists between runs)
const lastSeenId = $getWorkflowStaticData('global').lastSeenId || '';

// Filter: only VIDEO or REELS, only newer than last seen
const newVideos = [];
let newestId = lastSeenId;

for (const post of data) {
  if (post.media_type !== 'VIDEO' && post.media_type !== 'REELS') continue;
  if (post.id === lastSeenId) break; // hit previously seen, stop
  newVideos.push(post);
  if (!newestId || newestId === lastSeenId) newestId = post.id;
}

// Save newest ID so next run skips these
if (newestId && newestId !== lastSeenId) {
  $getWorkflowStaticData('global').lastSeenId = newestId;
}

console.log(`Found ${newVideos.length} new video(s) to cross-post`);

if (newVideos.length === 0) {
  return [{ json: { skip: true, message: 'No new videos' } }];
}

return newVideos.map(v => ({ json: v }));

// Generate platform-specific captions using the IG caption as base
const post = $input.first().json;
const baseCaption = post.caption || '';
const title = baseCaption.split('\n')[0].slice(0, 100) || 'New video';

// TikTok: short + punchy + hashtags (keep IG hashtags if present)
const hashtags = (baseCaption.match(/#[\w]+/g) || []).slice(0, 5).join(' ');
const cleanCaption = baseCaption.replace(/#[\w]+/g, '').trim().slice(0, 200);

const tiktokCaption = (cleanCaption.slice(0, 150) + ' ' + hashtags).trim().slice(0, 300);

// YouTube: descriptive title + longer desc
const youtubeTitle = title.slice(0, 100);
const youtubeDesc = `${cleanCaption}\n\n📸 Follow on Instagram: @alanoderso\n\n${hashtags}`;

return [{
  json: {
    ...post,
    tiktokCaption,
    youtubeTitle,
    youtubeDesc,
    videoUrl: post.media_url,
    title: youtubeTitle
  }
}];

const result = $input.first().json;
const post = $('generate-captions').first().json;

console.log('✅ Posted to TikTok + YouTube:', post.permalink);
console.log('Upload-Post response:', JSON.stringify(result));

return [{ json: { 
  success: true, 
  ig_post: post.permalink,
  request_id: result.request_id,
  platforms: result.platforms,
  timestamp: new Date().toISOString()
}}];

